// Turn the model's reply into a clean { tags: [...] } payload.
const res = $input.first().json;
const raw = res?.choices?.[0]?.message?.content ?? res?.content ?? '';
let text = String(raw).trim();
let tags = [];
const m = text.match(/\[[\s\S]*\]/);
if (m) { try { tags = JSON.parse(m[0]); } catch (e) {} }
if (!Array.isArray(tags) || !tags.length) { tags = text.split(/[,\n]/); }
tags = tags
  .map((t) => String(t).replace(/["'.\[\]]/g, '').trim().toUpperCase())
  .filter(Boolean)
  .slice(0, 3);
return [{ json: { tags } }];
